from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct
from typing import Optional
import os
import secrets
import time

app = FastAPI(title="Ethereum Signature Auth Service")

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
nonces = {}

class ChallengeRequest(BaseModel):
    address: str = Field(..., description="Ethereum wallet address")
    chain_id: Optional[int] = Field(None, description="Optional chain id")

class ChallengeResponse(BaseModel):
    address: str
    nonce: str
    message: str
    expires_at: int

class VerifyRequest(BaseModel):
    address: str = Field(..., description="Ethereum wallet address")
    signature: str = Field(..., description="Signed message signature")
    nonce: str = Field(..., description="Nonce that was issued in the challenge")

class VerifyResponse(BaseModel):
    authenticated: bool
    address: str
    recovered_address: str

def normalize_address(address: str) -> str:
    if not Web3.is_address(address):
        raise HTTPException(status_code=400, detail="Invalid Ethereum address")
    return Web3.to_checksum_address(address)

def build_message(address: str, nonce: str) -> str:
    return f"Sign this message to authenticate.\n\nAddress: {address}\nNonce: {nonce}"

@app.post("/challenge", response_model=ChallengeResponse)
def challenge(req: ChallengeRequest):
    address = normalize_address(req.address)
    nonce = secrets.token_urlsafe(16)
    expires_at = int(time.time()) + NONCE_TTL_SECONDS
    nonces[address.lower()] = {"nonce": nonce, "expires_at": expires_at}
    message = build_message(address, nonce)
    return ChallengeResponse(address=address, nonce=nonce, message=message, expires_at=expires_at)

@app.post("/verify", response_model=VerifyResponse)
def verify(req: VerifyRequest):
    address = normalize_address(req.address)
    stored = nonces.get(address.lower())
    if not stored:
        raise HTTPException(status_code=400, detail="No active challenge for this address")
    if stored["nonce"] != req.nonce:
        raise HTTPException(status_code=400, detail="Invalid nonce")
    if stored["expires_at"] < int(time.time()):
        nonces.pop(address.lower(), None)
        raise HTTPException(status_code=400, detail="Nonce expired")

    message = build_message(address, req.nonce)
    try:
        encoded_message = encode_defunct(text=message)
        recovered = Web3.to_checksum_address(Web3().eth.account.recover_message(encoded_message, signature=req.signature))
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid signature")

    if recovered.lower() != address.lower():
        raise HTTPException(status_code=401, detail="Signature does not match address")

    nonces.pop(address.lower(), None)
    return VerifyResponse(authenticated=True, address=address, recovered_address=recovered)

@app.get("/health")
def health():
    return {"status": "ok"}